INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('elementary-d0d1b9a2-moex-00075', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-114-34c7f7f6', 'sub-elementary-d0d1b9a2-02', NULL, 'single_choice', '「很多人不再有時間去認識東西。他們在商人那裡買現成的東西，但是因為商人並不販賣朋 友，所以很多人沒有朋友。」 根據上文，下列選項最符合文意的是：', '["很多人以為友情是可以用金錢換取，但真正的朋友是無價的", "因為朋友尚未商品化，所以人們無法透過便捷的方式來交友", "人們為了追求速成，不想花時間了解彼此並且等待關係成熟", "工商社會情感淺薄，人際關係疏離因而衍生對朋友過度期待"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:44+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "511", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00076', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-114-34c7f7f6', 'sub-elementary-d0d1b9a2-02', NULL, 'single_choice', '下列詩句中，何者沒有表達出詩人的自負感和孤獨感？', '["得歡當作樂，斗酒聚比鄰", "前不見古人，後不見來者", "舉杯邀明月，對影成三人", "敏捷詩千首，飄零酒一杯"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:44+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "511", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00077', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-114-34c7f7f6', 'sub-elementary-d0d1b9a2-02', NULL, 'single_choice', '孟浩然〈春曉〉：「春眠不覺曉，處處聞啼鳥。夜來風雨聲，花落知多少？」 下列解讀，何者完全正確？', '["詩中以擬人化手法揣摩群鳥啼聲，如在討論今晚風雨又將掃落多少花瓣", "作品中透過酣睡與鳥鳴，營造出春日氣候宜人，充滿了生意盎然的氣息", "詩中洋溢惜春、惜禽鳥、惜光陰之情，擔憂風雨中的群鳥是否得以遮蔽", "作品中描繪大地的沉睡與甦醒，延伸出人在季節中體悟自然變化的感動"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:44+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "511", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00078', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-114-34c7f7f6', 'sub-elementary-d0d1b9a2-02', NULL, 'single_choice', '「皮膚是人體合成、貯藏及釋放維生素D最重要的器官。皮膚需靠紫外線照射來合成維生素 D，再經由肝臟及腎臟代謝，形成較強活性的維生素D。維生素D缺乏，在小孩子會造成佝 僂病，在大人會產生強直性痙攣或軟骨病。小孩子可能是由於照射陽光太少引起，老年人由 於製造維生素D量減少且常使用防曬油，因此也容易造成維生素D缺乏。」 根據上文，下列選項何者正確？', '["攝取過多維生素D，極容易造成肝臟及腎臟的病變", "人體無法自行合成維生素D，必需靠口服補充劑維持", "缺乏維生素D的結果，容易導致多種與骨骼有關的疾病", "紫外線造成維生素D缺乏，要避免照射陽光及使用防曬油"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:44+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "511", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00079', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-114-34c7f7f6', 'sub-elementary-d0d1b9a2-02', NULL, 'single_choice', '「因為沒有家人或個性問題，與人群疏遠的高齡獨居者，藉由不斷地犯罪以求入獄。在獄中 有三餐可吃，也不必擔心付不起房租或在路邊孤獨死；更因無親朋好友，既不必介意犯罪或 入獄帶來的道德壓力，還能確保衣食無虞。」 根據上文，下列選項最符合防範高齡犯罪的方法是：', '["提高集合式住宅比例", "健全社會的人際網絡", "發放愛心待用的便當", "改善醫療服務的品質"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:44+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "511", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00080', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-114-34c7f7f6', 'sub-elementary-d0d1b9a2-02', NULL, 'single_choice', '「氣候變遷對於太平洋中的島國吐瓦魯是人民生活中天天面臨的威脅。第二十七屆聯合國氣 候峰會（COP27）期間，吐瓦魯外交部長柯飛宣布，將建立全球第一個元宇宙國家，把該國 珍貴的歷史、文化資產保存在雲端。吐瓦魯這項創舉，同時也代表沉痛的呼籲，全球若無法 合作以扭轉暖化趨勢，將有更多大城市淪陷，步上吐瓦魯的後塵。」 根據上文，下列選項何者最符合文意？', '["吐瓦魯積極尋求永續發展", "全球氣候暖化現象已趨緩", "建立元宇宙，才可以扭轉暖化趨勢", "面對氣候變遷，是全球的共同責任"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:44+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "511", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00081', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-114-34c7f7f6', 'sub-elementary-d0d1b9a2-02', NULL, 'single_choice', '「在日本，食品企業向批發商和零售商發送商品時，若是紙箱等包裝出現損壞和汙垢將被退 貨，待全面檢查、重新包裝之後再度出貨。但新的生產批次商品已經發送到零售方，因此就 只能把較舊的商品廢棄。由於外觀判斷沒有明確的標準，為了減少過度退貨而造成食物浪費， 商人們開始採用AI圖像識別的技術，透過智慧手機拍攝紙箱外觀，由AI找出存在膨脹和水 漬等疑似汙損的部位。然後再經由資料庫與過去的破損案例比較，對是否應退貨作出判斷， 成本也有望得到控制。」 根據上文，下列選項最符合文意的是：', '["會將包裝破損的商品退貨重檢，是基於商品美觀的考量", "由於批次舊的商品經過重新包裝，因此不受零售方歡迎", "商品外觀檢測的標準不明確，容易讓人工檢測趨於鬆散", "AI判斷退貨的精準度較佳，因而能減少過度退貨的情形"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:44+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "511", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00082', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-114-34c7f7f6', 'sub-elementary-d0d1b9a2-02', NULL, 'single_choice', '「世界上似乎有兩類人，他們性格不同：一類人有很強的信仰，而不大需要知識來支持信仰； 對這類人而言，知識有時反而是一個障礙。學問愈深，知識愈多，便愈會被名詞、概念所糾 纏而見不到真實的道體。所以陸象山才說朱子『學不見道，枉費精神。』另外一類人，並不 是沒有信仰，不過他們總想把信仰建築在堅實的知識的基礎上，總要搞清楚信仰的根據 何在。」 根據上文，關於作者所區分兩類人的差異，敘述最適當的是：', '["學術信仰是否堅定", "學識積累是否需要", "處事方式是否以簡御繁", "思考問題是否注重程序"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:44+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "511", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00083', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-114-34c7f7f6', 'sub-elementary-d0d1b9a2-02', NULL, 'single_choice', '賈伯斯說：「並不是每個人都需要種植自己的糧食，也不是每個人都需要做自己穿的衣服， 我們說著別人發明的語言，使用別人發明的數學……我們一直在使用別人的成果，使用人類 已有的經驗和知識來進行發明創造，是一件很了不起的事情。」 依據上文，下列選項何者正確？', '["立足於既有的經驗進行價值創新", "擁有供應方實現對供應鏈的掌控", "統合資源與人才提升產業競爭力", "強化溝通能力才能滿足客戶需求"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:44+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "511", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL),
  ('elementary-d0d1b9a2-moex-00084', 'elementary-d0d1b9a2', 'elementary-d0d1b9a2-moex-114-34c7f7f6', 'sub-elementary-d0d1b9a2-02', NULL, 'single_choice', '「過去我在醫學院讀書時，教科書是依照組織、系統、疾病作為分類的脈絡的。厚厚一疊又 一疊的原文書，難懂又索然無味，為了考試，還是要咬牙切齒地吸收。奇怪的是，到醫院實 習開始照顧病人之後，只要跟病人的疾病相關的內容，無論過去覺得多麼艱澀難懂的學問， 忽然之間閱讀起來都變得有趣，也非常容易就理解了。」 根據上文，造成作者感受如此懸殊的最主要原因是：', '["明白人生先苦後甘的常態", "找到了讀書的價值與意義", "發現可以舉一反三的趣味", "對於實作的喜愛優於讀書"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:44+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "511", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "會計"}'::jsonb, NULL)
